        if (!serviceType.service_type_id) {
          const requestBody = {
            service_name: selectedService.service_name,
            service_type_name: serviceType.service_type_name,
            pricing: serviceType.pricing_fields.map((field: any) => ({
              room_size: field.room_size,
              price: field.price
            }))
          };

          await apiService.post(API_ENDPOINTS.ADD_SERVICE_TYPE, requestBody);
          continue;
        }

        // Find the original service type to compare
        const originalType = originalServiceTypes.find((original: any) => 
          original.service_type_id === serviceType.service_type_id
        );

        if (originalType) {
          // Handle service type name update if changed
          if (originalType.service_type_name !== serviceType.service_type_name) {
            await apiService.post(API_ENDPOINTS.UPDATE_SERVICE_TYPE, {
              service_type_id: serviceType.service_type_id,
