                    value={editServiceForm.service_name}
                    onChange={(e) => setEditServiceForm({...editServiceForm, service_name: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                    placeholder="Enter service name"
                  />
                </div>

                {/* Service Description */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Description
                  </label>
                  <textarea
                    value={editServiceForm.description}
                    onChange={(e) => setEditServiceForm({...editServiceForm, description: e.target.value})}
                    rows={4}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors resize-none"
                    placeholder="Enter service description"
                  />
                </div>

                {/* Service Locations */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Locations
                  </label>
                  <input
                    type="text"
                    value={editServiceForm.locations}
                    onChange={(e) => setEditServiceForm({...editServiceForm, locations: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 transition-colors"
                    placeholder="Enter service locations (comma separated)"
                  />
                  <p className="text-sm text-gray-500 mt-1">
                    Enter locations where this service is available, separated by commas
                  </p>
                </div>

                {/* Action Buttons */}
                <div className="flex justify-end space-x-3 pt-4 border-t">
                  <button
                    onClick={() => setEditServiceModalOpen(false)}
                    className="px-6 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={saveServiceDetails}
                    disabled={editServiceLoading}
                    className="px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                  >
                    {editServiceLoading ? (
                      <>
                        <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                        Saving...
                      </>
                    ) : (
                      <>
                        <FiSave className="w-4 h-4 mr-2" />
                        Save Changes
                      </>
                    )}
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Add Offer Modal */}
      {addOfferModalOpen && (
        <div className="fixed inset-0 bg-black bg-opacity-60 flex items-center justify-center z-50 p-2 sm:p-4">
          <div className="bg-white rounded-xl shadow-2xl w-full max-w-2xl mx-2 sm:mx-4 max-h-[90vh] overflow-hidden">
            {/* Header */}
            <div className="flex items-center justify-between p-4 sm:p-6 border-b border-gray-200 bg-gradient-to-r from-teal-50 to-blue-50">
              <div className="flex items-center space-x-3">
                <div className="p-2 bg-teal-100 rounded-lg">
                  <FiGift className="w-6 h-6 text-teal-600" />
                </div>
                <div>
                  <h2 className="text-xl sm:text-2xl font-bold text-gray-900">
                    Add New Offer
                  </h2>
                  <p className="text-sm text-gray-600 mt-1">
                    Create a new promotional offer
                  </p>
                </div>
              </div>
              <button
                onClick={() => setAddOfferModalOpen(false)}
                className="p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 rounded-lg transition-colors"
                title="Close"
              >
                <FiX className="w-5 h-5" />
              </button>
            </div>

            <div className="p-4 sm:p-6 overflow-y-auto max-h-[calc(90vh-120px)]">
              <div className="space-y-6">
                {/* Offer Name */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Offer Name *
                  </label>
                  <input
                    type="text"
                    value={addOfferForm.offer_name}
                    onChange={(e) => setAddOfferForm({...addOfferForm, offer_name: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors"
                    placeholder="Enter offer name"
                  />
                </div>

                {/* Coupon Number */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Coupon Number *
                  </label>
                  <input
                    type="text"
                    value={addOfferForm.coupon_number}
                    onChange={(e) => setAddOfferForm({...addOfferForm, coupon_number: e.target.value})}
                    className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors"
                    placeholder="e.g., AS34ejJ@qw"
                  />
                </div>

                {/* Date Range */}
                <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Start Date *
                    </label>
                    <input
                      type="date"
                      value={addOfferForm.offer_starts_on}
                      onChange={(e) => setAddOfferForm({...addOfferForm, offer_starts_on: e.target.value})}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors"
                    />
                  </div>
                  <div>
                    <label className="block text-sm font-medium text-gray-700 mb-2">
                      Expiry Date *
                    </label>
                    <input
                      type="date"
                      value={addOfferForm.expires_on}
                      onChange={(e) => setAddOfferForm({...addOfferForm, expires_on: e.target.value})}
                      className="w-full px-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors"
                    />
                  </div>
                </div>

                {/* Offer Percentage */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Discount Percentage *
                  </label>
                  <div className="relative">
                    <input
                      type="number"
                      value={addOfferForm.offer_percentage}
                      onChange={(e) => setAddOfferForm({...addOfferForm, offer_percentage: e.target.value})}
                      className="w-full pl-8 pr-4 py-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-teal-500 focus:border-teal-500 transition-colors"
                      placeholder="0"
                      min="0"
                      max="100"
                      step="0.01"
                    />
                    <span className="absolute left-3 top-3 text-gray-500">%</span>
                  </div>
                </div>

                {/* Offer Banner */}
                <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">
                    Offer Banner *
                  </label>

                  {offerBannerPreview ? (
                    // Banner Preview
                    <div className="relative">
                      <div className="border-2 border-teal-300 rounded-lg p-4 bg-gray-50">
                        <div className="flex items-center justify-between mb-3">
                          <span className="text-sm font-medium text-gray-700">Banner Preview</span>
                          <button
                            type="button"
                            onClick={clearOfferBanner}
                            className="text-red-600 hover:text-red-800 text-sm font-medium flex items-center"
                          >
                            <FiX className="w-4 h-4 mr-1" />
                            Clear
                          </button>
                        </div>
                        <div className="relative">
                          <img 
                            src={offerBannerPreview} 
                            alt="Banner Preview" 
                            className="w-full h-32 object-cover rounded border"
                          />
                          <div className="absolute top-2 right-2 bg-black bg-opacity-50 text-white text-xs px-2 py-1 rounded">
                            {selectedOfferFile?.name}
                          </div>
                        </div>
                      </div>
                    </div>
                  ) : (
                    // Upload Area
                    <div className="border-2 border-dashed border-teal-300 rounded-lg p-6 text-center hover:border-teal-400 transition-colors">
                      <input
                        type="file"
                        onChange={handleOfferFileSelect}
                        accept="image/*,.pdf"
                        className="hidden"
                        id="offer-banner-input"
                      />
                      <label htmlFor="offer-banner-input" className="cursor-pointer">
                        <div className="space-y-3">
                          <div className="mx-auto w-12 h-12 bg-teal-100 rounded-full flex items-center justify-center">
                            <FiPlus className="w-6 h-6 text-teal-600" />
                          </div>
                          <div>
                            <p className="text-sm text-gray-600">
                              Choose file to upload (JPG, PNG, or PDF)
                            </p>
                            <p className="text-xs text-gray-500 mt-1">
                              Click to browse or drag and drop
                            </p>
                          </div>
                        </div>
                      </label>
                    </div>
                  )}
                </div>

                {/* Action Buttons */}
                <div className="flex justify-end space-x-3 pt-4 border-t">
                  <button
                    onClick={() => setAddOfferModalOpen(false)}
                    className="px-6 py-2 bg-gray-600 text-white rounded-lg hover:bg-gray-700 transition-colors"
                  >
                    Cancel
                  </button>
                  <button
                    onClick={saveOffer}
                    disabled={addOfferLoading}
                    className="px-6 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed flex items-center"
                  >
                    {addOfferLoading ? (
                      <>
                        <div className="animate-spin rounded-full h-4 w-4 border-b-2 border-white mr-2"></div>
                        Adding...
                      </>
                    ) : (
                      <>
                        <FiSave className="w-4 h-4 mr-2" />
                        Add Offer
                      </>
                    )}
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default AdminDashboard;
